# ---------------------------------------------------------------------------
# Database Models — Prediction
# ---------------------------------------------------------------------------
# models/prediction_model.py
#
# Each row stores one stress-prediction result generated by the ML model.
# Linked to a user via a foreign key.
# ---------------------------------------------------------------------------

from datetime import datetime
from extensions import db


class Prediction(db.Model):
    """SQLAlchemy model for the 'predictions' table."""

    __tablename__ = "predictions"

    # ── Primary Key ──────────────────────────────────────────────────────────
    id      = db.Column(db.Integer, primary_key=True, autoincrement=True)
    user_id = db.Column(db.Integer, db.ForeignKey("users.id"), nullable=False, index=True)

    # ── Input Features ───────────────────────────────────────────────────────
    sleep_hours       = db.Column(db.Float, nullable=True)
    working_hours     = db.Column(db.Float, nullable=True)
    work_pressure     = db.Column(db.Float, nullable=True)   # 1–10 scale
    physical_activity = db.Column(db.Float, nullable=True)   # hrs / week
    remote_work       = db.Column(db.Boolean, nullable=True)
    emotion_score     = db.Column(db.Float, nullable=True)   # 0–100
    fatigue_score     = db.Column(db.Float, nullable=True)   # 0–100
    focus_score       = db.Column(db.Float, nullable=True)   # 0–100

    # ── Output / Results ─────────────────────────────────────────────────────
    stress_level      = db.Column(db.String(20), nullable=False)   # Low / Moderate / High
    stress_score      = db.Column(db.Float, nullable=False)        # 0–100
    burnout_risk      = db.Column(db.String(20), nullable=True)    # Low / Moderate / High
    wellness_score    = db.Column(db.Float, nullable=True)         # 0–100
    emotional_state   = db.Column(db.String(50), nullable=True)

    # ── Recommendations (stored as JSON string) ───────────────────────────────
    recommendations   = db.Column(db.Text, nullable=True)

    # ── Timestamp ────────────────────────────────────────────────────────────
    created_at = db.Column(db.DateTime, default=datetime.utcnow, index=True)

    # ── Serialisation ────────────────────────────────────────────────────────
    def to_dict(self) -> dict:
        import json
        recs = []
        if self.recommendations:
            try:
                recs = json.loads(self.recommendations)
            except Exception:
                recs = [self.recommendations]

        return {
            "id":                self.id,
            "user_id":           self.user_id,
            "sleep_hours":       self.sleep_hours,
            "working_hours":     self.working_hours,
            "work_pressure":     self.work_pressure,
            "physical_activity": self.physical_activity,
            "remote_work":       self.remote_work,
            "emotion_score":     self.emotion_score,
            "fatigue_score":     self.fatigue_score,
            "focus_score":       self.focus_score,
            "stress_level":      self.stress_level,
            "stress_score":      self.stress_score,
            "burnout_risk":      self.burnout_risk,
            "wellness_score":    self.wellness_score,
            "emotional_state":   self.emotional_state,
            "recommendations":   recs,
            "created_at":        self.created_at.isoformat() if self.created_at else None,
        }

    def __repr__(self) -> str:
        return f"<Prediction id={self.id} user_id={self.user_id} stress={self.stress_level}>"


# ---------------------------------------------------------------------------
# Emotion Log — stores raw facial-emotion data per session
# ---------------------------------------------------------------------------
class EmotionLog(db.Model):
    """Raw emotion capture data per frame / session."""

    __tablename__ = "emotion_logs"

    id         = db.Column(db.Integer, primary_key=True, autoincrement=True)
    user_id    = db.Column(db.Integer, db.ForeignKey("users.id"), nullable=False, index=True)

    # Emotion scores (0–100 each, as captured from DeepFace / frontend)
    happy      = db.Column(db.Float, default=0.0)
    sad        = db.Column(db.Float, default=0.0)
    angry      = db.Column(db.Float, default=0.0)
    neutral    = db.Column(db.Float, default=0.0)
    fear       = db.Column(db.Float, default=0.0)
    disgust    = db.Column(db.Float, default=0.0)
    surprise   = db.Column(db.Float, default=0.0)

    # Derived values
    dominant_emotion = db.Column(db.String(30), nullable=True)
    emotion_score    = db.Column(db.Float, nullable=True)   # overall composite
    fatigue_level    = db.Column(db.String(20), nullable=True)

    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    def to_dict(self) -> dict:
        return {
            "id":               self.id,
            "user_id":          self.user_id,
            "happy":            self.happy,
            "sad":              self.sad,
            "angry":            self.angry,
            "neutral":          self.neutral,
            "fear":             self.fear,
            "disgust":          self.disgust,
            "surprise":         self.surprise,
            "dominant_emotion": self.dominant_emotion,
            "emotion_score":    self.emotion_score,
            "fatigue_level":    self.fatigue_level,
            "created_at":       self.created_at.isoformat() if self.created_at else None,
        }
